建圖方式直接決定怎麼枚舉鄰居，常見有三種建模：

**1. 網格圖 → 方向陣列**
把每格 `(r, c)` 當節點，用方向陣列枚舉鄰格：
```cpp
int dr[4] = {-1, 1, 0, 0};
int dc[4] = {0, 0, -1, 1};
for (int k = 0; k < 4; ++k) {
    int nr = r + dr[k], nc = c + dc[k];
    if (nr < 0 || nr >= R || nc < 0 || nc >= C) continue; // 越界
    if (grid[nr][nc] == '#') continue;                    // 障礙
    // 將 (nr, nc) 入隊
}
```
逐行：`dr/dc` 定義上下左右（八方向再加四組對角）；先檢查越界、再檢查是否可走，最後才入隊。

**2. 隱式圖（如單詞接龍）→ 枚舉鄰居 + 雜湊判重**
節點不顯式存在，鄰居由規則生成（改一個字母）。用 `unordered_map/unordered_set` 把字串映射成是否已訪問，邊在枚舉時即時產生。

**3. 狀態圖（如走迷宮帶鑰匙）→ 狀態壓縮**
節點 = `(位置, 已持有鑰匙的 bitmask)`。同一格子在不同鑰匙狀態下是**不同節點**，visited 要開成 `visited[r][c][1 << keys]`，否則會誤判已訪問而漏解。

DFS 樹上定義 `disc[v]`（首次訪問時間）和 `low[v]`（v 子樹能回溯到的最早祖先時間）。

**橋（Bridge）**：邊 (u,v) 是橋，若 `low[v] > disc[u]`，即 v 的子樹無法繞回 u 之前。

**割點（Articulation Point）**：節點 u 是割點，若存在子節點 v 使得 `low[v] >= disc[u]`（根節點需有 ≥ 2 個子樹）。

```cpp
void dfs_bridge(int u, int parent, vector<bool>& visited,
                vector<int>& disc, vector<int>& low, int& timer,
                vector<pair<int,int>>& bridges) {
    visited[u] = true;
    disc[u] = low[u] = timer++;
    for (int v : graph[u]) {
        if (!visited[v]) {
            dfs_bridge(v, u, visited, disc, low, timer, bridges);
            low[u] = min(low[u], low[v]);
            if (low[v] > disc[u]) bridges.push_back({u, v}); // Bridge found
        } else if (v != parent) {
            low[u] = min(low[u], disc[v]); // Back edge
        }
    }
}
```

Tarjan 算法在一次 DFS 中找出所有 SCC，利用 `low` 值和 stack 追蹤當前路徑：

```cpp
void tarjan(int u, vector<int>& disc, vector<int>& low,
            stack<int>& st, vector<bool>& on_stack,
            int& timer, vector<vector<int>>& sccs) {
    disc[u] = low[u] = timer++;
    st.push(u); on_stack[u] = true;
    for (int v : graph[u]) {
        if (disc[v] == -1) { // Unvisited
            tarjan(v, disc, low, st, on_stack, timer, sccs);
            low[u] = min(low[u], low[v]);
        } else if (on_stack[v]) {
            low[u] = min(low[u], disc[v]); // Back edge within SCC
        }
    }
    if (low[u] == disc[u]) { // Root of SCC
        vector<int> scc;
        while (true) { int v = st.top(); st.pop(); on_stack[v] = false; scc.push_back(v); if (v == u) break; }
        sccs.push_back(scc);
    }
}
```
⚠️ low 的更新只考慮 back edge（on_stack 中的節點），不更新 cross edge，這是 Tarjan 與 Kosaraju 的關鍵差異。

template_code:
vector<int> bfs(int start, const vector<vector<int>>& graph) {
    vector<int> dist(graph.size(), -1); // -1 means unvisited
    queue<int> q;
    dist[start] = 0; // Source distance is zero
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : graph[u]) {
            if (dist[v] != -1) continue; // Each node enters queue once
            dist[v] = dist[u] + 1; // BFS layer increases by one
            q.push(v);
        }
    }
    return dist;
}

void dfs(int u, const vector<vector<int>>& graph, vector<int>& seen) {
    seen[u] = 1; // Mark before visiting neighbors
    for (int v : graph[u]) {
        if (!seen[v]) dfs(v, graph, seen);
    }
}

