vector<pair<int, int>> merge_intervals(vector<pair<int, int>> intervals) {
    sort(intervals.begin(), intervals.end()); // Sort by left endpoint first
    vector<pair<int, int>> merged;
    for (auto [l, r] : intervals) {
        if (merged.empty() || merged.back().second < l) {
            merged.push_back({l, r}); // No overlap with previous interval
        } else {
            merged.back().second = max(merged.back().second, r); // Extend coverage
        }
    }
    return merged;
}

vector<long long> difference_apply(int n, vector<array<int, 3>> ops) {
    vector<long long> diff(n + 1);
    for (auto [l, r, delta] : ops) {
        diff[l] += delta; // Range starts gaining delta
        if (r + 1 < n) diff[r + 1] -= delta; // Range stops after r
    }
    for (int i = 1; i < n; ++i) diff[i] += diff[i - 1]; // Prefix restores values
    diff.pop_back();
    return diff;
}

