帶權並查集在父指標上額外記錄『到父節點的權值』，`find` 時把沿途權值累加成『到根的偏移』，可解食物鏈、差值等式類問題：
```cpp
int find(int x) {
    if (parent[x] == x) return x;
    int root = find(parent[x]);
    rel[x] += rel[parent[x]]; // 把到父的偏移累加成到根的偏移
    parent[x] = root;          // 路徑壓縮
    return root;
}
```
逐行：先遞迴求父的根（此時 `rel[parent[x]]` 已是父到根的偏移）；把 `rel[x]` 累加上父到根的值，得到 x 到根的偏移；再把 x 直接掛到根。`union(a, b, w)`（表示 b − a = w）時，先 find 兩端的根，再依 `rel[a]`、`rel[b]`、`w` 推出兩根之間應設的權值。

template_code:
struct DSU {
    vector<int> parent, size;
    DSU(int n) : parent(n), size(n, 1) {
        iota(parent.begin(), parent.end(), 0); // Every node starts as its own root
    }
    int find(int x) {
        if (parent[x] == x) return x;
        return parent[x] = find(parent[x]); // Path compression
    }
    bool unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b) return false;
        if (size[a] < size[b]) swap(a, b); // Attach smaller tree to larger tree
        parent[b] = a;
        size[a] += size[b];
        return true;
    }
};

deep_dive.body:
LCA 查詢分兩階段，都靠二進位分解：
```cpp
int lca(int u, int v) {
    if (depth[u] < depth[v]) swap(u, v);      // 讓 u 較深
    int diff = depth[u] - depth[v];
    for (int k = 0; k < LOG; ++k)              // 階段一：把 u 提到與 v 同深度
        if (diff >> k & 1) u = up[u][k];
    if (u == v) return u;                       // v 是 u 的祖先
    for (int k = LOG - 1; k >= 0; --k)          // 階段二：高位到低位同步上跳
        if (up[u][k] != up[v][k]) { u = up[u][k]; v = up[v][k]; }
    return up[u][0];                            // 再跳一步即 LCA
}
```
逐行：先確保 u 較深，用 `diff` 的二進位把 u 上提對齊深度；若對齊後相等，v 本身就是 LCA；否則**從高位往低位**同步跳——只在『跳了之後兩者仍不相同』時才跳，保證停在 LCA 正下方，最後 `up[u][0]` 就是 LCA。階段二必須由高位往低位，才能逼近而不越過。

template_code:
const int LOG = 20;
vector<array<int, LOG>> up;
vector<int> depth;

void dfs_lift(int u, int p, const vector<vector<int>>& tree) {
    up[u][0] = p; // Immediate parent
    for (int k = 1; k < LOG; ++k) {
        up[u][k] = up[up[u][k - 1]][k - 1]; // Jump twice by 2^(k-1)
    }
    for (int v : tree[u]) {
        if (v == p) continue;
        depth[v] = depth[u] + 1;
        dfs_lift(v, u, tree);
    }
}

int kth_ancestor(int u, int k) {
    for (int bit = 0; bit < LOG; ++bit) {
        if (k >> bit & 1) u = up[u][bit]; // Apply binary decomposition
    }
    return u;
}

