單調棧題的關鍵在『何時記錄、何時結算』。以柱狀圖最大矩形為例，棧內保持下標對應高度遞增：
```cpp
stack<int> st;                 // 存下標，對應高度遞增
for (int i = 0; i <= n; ++i) {
    int h = (i == n) ? 0 : height[i];   // 末尾補 0 強制清空棧
    while (!st.empty() && height[st.top()] > h) {
        int top = st.top(); st.pop();
        int left = st.empty() ? -1 : st.top();         // 左邊界：新棧頂
        ans = max(ans, height[top] * (i - left - 1));  // 右邊界即 i
    }
    st.push(i);
}
```
逐行：遇到比棧頂矮的 `h`，代表棧頂柱子的『右邊第一個更矮』就是 i，於是**出棧時結算**——以 `height[top]` 為高、寬度 `(i - left - 1)`（左邊界是出棧後的新棧頂）。末尾補一個高度 0 確保所有柱子都被結算。記住順序：**入棧時只記下標，面積一律在出棧時計算**。

template_code:
vector<int> next_greater(const vector<int>& a) {
    vector<int> ans(a.size(), -1), st;
    for (int i = 0; i < (int)a.size(); ++i) {
        while (!st.empty() && a[st.back()] < a[i]) {
            ans[st.back()] = i; // Current i is the first greater element
            st.pop_back();
        }
        st.push_back(i); // Indices in stack have decreasing values
    }
    return ans;
}

vector<int> sliding_max(const vector<int>& a, int k) {
    deque<int> dq;
    vector<int> ans;
    for (int i = 0; i < (int)a.size(); ++i) {
        while (!dq.empty() && dq.front() <= i - k) dq.pop_front(); // Remove expired index
        while (!dq.empty() && a[dq.back()] <= a[i]) dq.pop_back(); // Remove dominated values
        dq.push_back(i);
        if (i >= k - 1) ans.push_back(a[dq.front()]);
    }
    return ans;
}

