```cpp
// Returns empty if negative cycle detected
vector<long long> bellman_ford(int src, int n, const vector<tuple<int,int,int>>& edges) {
    vector<long long> dist(n, LLONG_MAX);
    dist[src] = 0;
    for (int iter = 0; iter < n - 1; iter++) {
        bool updated = false;
        for (auto [u, v, w] : edges) {
            if (dist[u] != LLONG_MAX && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                updated = true;
            }
        }
        if (!updated) break; // Early termination
    }
    // Check for negative cycle (n-th relaxation round)
    for (auto [u, v, w] : edges)
        if (dist[u] != LLONG_MAX && dist[u] + w < dist[v])
            return {}; // Negative cycle exists
    return dist;
}
```

