struct Edge { int u, v, w; };
long long kruskal(int n, vector<Edge>& edges) {
    sort(edges.begin(), edges.end(), [](const Edge& a, const Edge& b) { return a.w < b.w; });
    DSU dsu(n);
    long long total = 0; int cnt = 0;
    for (auto& e : edges) {
