template_code:
// Kruskal MST
long long kruskal(int n, vector<tuple<int,int,int>>& edges) {
    sort(edges.begin(), edges.end()); // Sort by weight (first element)
    vector<int> parent(n); iota(parent.begin(), parent.end(), 0);
    function<int(int)> find = [&](int x) { return parent[x] == x ? x : parent[x] = find(parent[x]); };
    long long total = 0; int cnt = 0;
    for (auto& [w, u, v] : edges) {
        int pu = find(u), pv = find(v);
        if (pu != pv) { parent[pu] = pv; total += w; cnt++; }
    }
    return cnt == n - 1 ? total : -1;
}

