// Tree DP: maximum independent set
vector<array<int,2>> dp; // dp[v][0/1]: max independent set in subtree rooted at v
void dfs_indep(int u, int par, const vector<vector<int>>& tree) {
    dp[u] = {0, 1}; // Not select u: 0, select u: 1
    for (int v : tree[u]) {
        if (v == par) continue;
        dfs_indep(v, u, tree);
        dp[u][0] += max(dp[v][0], dp[v][1]); // u not selected: child can be either
        dp[u][1] += dp[v][0]; // u selected: child must not be selected
    }
}

