失敗函數 `fail[i]` = 模式串 p[0..i] 的最長「不等於自身的」真前綴等於真後綴的長度。

```cpp
vector<int> kmp_fail(const string& p) {
    int n = p.size();
    vector<int> fail(n, 0);
    for (int i = 1; i < n; i++) {
        int j = fail[i - 1];
        while (j > 0 && p[i] != p[j]) j = fail[j - 1]; // Fall back
        if (p[i] == p[j]) j++;
        fail[i] = j;
    }
    return fail;
}

vector<int> kmp_search(const string& text, const string& pattern) {
    string s = pattern + '#' + text; // '#' is a separator not in alphabet
    auto fail = kmp_fail(s);
    vector<int> matches;
    int m = pattern.size();
    for (int i = m + 1; i < (int)s.size(); i++)
        if (fail[i] == m) matches.push_back(i - 2 * m); // Match found
    return matches;
}
```

Z[i] = 字串 s 從位置 i 開始與 s 的最長公共前綴長度（Z[0] 定義為 0 或 n）。

```cpp
vector<int> z_function(const string& s) {
    int n = s.size();
    vector<int> z(n, 0);
    z[0] = n; // Convention: z[0] = n
    int l = 0, r = 0;
    for (int i = 1; i < n; i++) {
        if (i < r) z[i] = min(r - i, z[i - l]); // Use previous Z values
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) z[i]++;
        if (i + z[i] > r) { l = i; r = i + z[i]; } // Extend window
    }
    return z;
}
```

Z 函數模式匹配：對 `p + '#' + t` 計算 Z 函數，Z[i] == |p| 的位置即為匹配點。

