// Trie for prefix/dictionary queries
struct Trie {
    array<int, 26> ch;
    int cnt; // Count of words passing through this node
    Trie() : cnt(0) { ch.fill(-1); }
};
vector<Trie> trie = {Trie()};
void insert(const string& s) {
    int cur = 0;
    for (char c : s) {
        int idx = c - 'a';
        if (trie[cur].ch[idx] == -1) { trie[cur].ch[idx] = trie.size(); trie.push_back(Trie()); }
        cur = trie[cur].ch[idx];
        trie[cur].cnt++;
    }
}

