```cpp
int tsp(const vector<vector<int>>& dist) {
    int n = dist.size();
    int FULL = (1 << n) - 1;
    vector<vector<int>> dp(1<<n, vector<int>(n, INT_MAX/2));
    dp[1][0] = 0; // Start from node 0, visited = {0}
    for (int mask = 1; mask <= FULL; mask++) {
        for (int u = 0; u < n; u++) {
            if (!(mask >> u & 1) || dp[mask][u] == INT_MAX/2) continue;
            for (int v = 0; v < n; v++) {
                if (mask >> v & 1) continue; // Already visited
                int new_mask = mask | (1 << v);
                dp[new_mask][v] = min(dp[new_mask][v], dp[mask][u] + dist[u][v]);
            }
        }
    }
    int ans = INT_MAX;
    for (int u = 1; u < n; u++) ans = min(ans, dp[FULL][u] + dist[u][0]); // Return to start
    return ans;
}
```

計算每個集合 S 的「所有子集的值之和」：`f[S] = Σ g[T] for T ⊆ S`。

```cpp
// SOS DP: f[S] = sum of g[T] for all T subset of S
vector<long long> f(1<<n);
for (int i = 0; i < (1<<n); i++) f[i] = g[i]; // Initialize with base values
for (int i = 0; i < n; i++) // Process each bit
    for (int S = 0; S < (1<<n); S++)
        if (S >> i & 1) f[S] += f[S ^ (1<<i)]; // Add contribution of i-th bit
```

