// 2D vector with cross and dot product
struct Vec2 {
    long long x, y;
    Vec2(long long x=0, long long y=0) : x(x), y(y) {}
    Vec2 operator-(const Vec2& b) const { return {x-b.x, y-b.y}; }
    long long cross(const Vec2& b) const { return x*b.y - y*b.x; } // Cross product
    long long dot(const Vec2& b) const { return x*b.x + y*b.y; }   // Dot product
    long long norm2() const { return x*x + y*y; }                   // Squared length
};
